#[test]
fn fr016_source_timer_arm_and_required_rights_remain_semantic() {
    let source = trace(Stage1TraceRole::Source, 47_000_000, 50_000_000);
    let normalized = normalize_trace(source.clone());

    assert_eq!(timer_status_remaining(&normalized.base_state), 1);
    assert_eq!(timer_status_remaining(&normalized.final_state), 1);
    let request = prepared_request(&normalized.entries[0]);
    assert_eq!(timer_arm_remaining(request), 50_000_000);
    assert_eq!(request.request_digest, Digest::ZERO);
    assert_eq!(normalized.entries[0].input_state, Digest::ZERO);
    assert_eq!(normalized.entries[0].output_state, Digest::ZERO);
    assert_eq!(normalized.final_state.evidence[0].digest, Digest::ZERO);

    let changed_initial_arm =
        normalize_trace(trace(Stage1TraceRole::Source, 47_000_000, 49_000_000));
    assert_ne!(normalized, changed_initial_arm);

    let mut changed_rights = source;
    changed_rights.base_state.timer.claim.required_rights = Rights::TIMER_ARM;
    changed_rights.final_state.timer.claim.required_rights = Rights::TIMER_ARM;
    assert_ne!(normalized, normalize_trace(changed_rights));
}

#[test]
fn fr016_timer_positive_values_collapse_but_zero_vs_positive_is_retained() {
    let positive_a = normalize_trace(trace(Stage1TraceRole::Destination, 41, 41));
    let positive_b = normalize_trace(trace(Stage1TraceRole::Destination, 9_000, 9_000));
    assert_eq!(positive_a, positive_b);
    assert_eq!(timer_arm_remaining(prepared_request(&positive_a.entries[0])), 1);

    let zero = normalize_trace(trace(Stage1TraceRole::Destination, 0, 0));
    assert_ne!(positive_a, zero);
}

#[test]
fn fr016_event_order_and_effect_identity_are_retained() {
    let mut first = trace(Stage1TraceRole::Source, 1, 50_000_000);
    let mut second = first.entries[0].clone();
    second.position = JournalPosition(2);
    second.event.identity = Identity::from_u128(88);
    first.entries.push(second);
    let ordered = normalize_trace(first.clone());
    first.entries.swap(0, 1);
    assert_ne!(ordered, normalize_trace(first));

    let mut changed_operation = trace(Stage1TraceRole::Source, 1, 50_000_000);
    if let EventKind::EffectPrepared { request } = &mut changed_operation.entries[0].event.kind {
        request.operation = Identity::from_u128(999);
    }
    assert_ne!(
        normalize_trace(trace(Stage1TraceRole::Source, 1, 50_000_000)),
        normalize_trace(changed_operation)
    );
}

#[test]
fn strict_normalizer_rejects_nested_unknown_trace_and_snapshot_fields() {
    let root = temp_dir("unknown-fields");
    fs::create_dir_all(&root).unwrap();

    let mut trace_value =
        serde_json::to_value(trace(Stage1TraceRole::Source, 1, 50_000_000)).unwrap();
    trace_value["entries"][0]["event"]["kind"]["effect_prepared"]
        .as_object_mut()
        .unwrap()
        .insert("future_field".to_owned(), serde_json::Value::Bool(true));
    fs::write(root.join("trace.json"), serde_json::to_vec(&trace_value).unwrap()).unwrap();
    assert!(read_typed_artifact::<Stage1SemanticTraceArtifact>(&root, "trace.json").is_err());

    let mut snapshot_value = serde_json::to_value(snapshot()).unwrap();
    snapshot_value["body"]["snapshot"]
        .as_object_mut()
        .unwrap()
        .insert("future_field".to_owned(), serde_json::Value::Bool(true));
    fs::write(root.join("snapshot.json"), serde_json::to_vec(&snapshot_value).unwrap()).unwrap();
    assert!(read_typed_artifact::<SnapshotEnvelope>(&root, "snapshot.json").is_err());

    fs::remove_dir_all(root).unwrap();
}

#[test]
fn fr016_pid_and_human_worker_message_are_excluded_but_worker_code_retryable_provider_adapter_workload_role_and_order_are_retained()
 {
    let root = temp_dir("worker-errors");
    let _ = fs::remove_dir_all(&root);
    fs::create_dir_all(root.join("cases/safe-point-unreachable/raw")).unwrap();
    fs::write(root.join("cases/safe-point-unreachable/raw/assertions.jsonl"), b"").unwrap();
    let case = worker_error_case();
    let baseline_error = WorkerErrorFixture::baseline("engine-specific diagnostic A");

    write_worker_error_transcripts(&root, &[baseline_error], &[], 10, 11);
    let baseline = read_worker_errors(&case, &root).unwrap();
    assert_eq!(baseline.len(), 1);

    let mut excluded = baseline_error;
    excluded.message = "different human diagnostic B";
    write_worker_error_transcripts(&root, &[excluded], &[], 999, 11);
    assert_eq!(baseline, read_worker_errors(&case, &root).unwrap());

    for mutation in [
        WorkerErrorFixture { code: "runtime", ..baseline_error },
        WorkerErrorFixture { retryable: Some(true), ..baseline_error },
        WorkerErrorFixture { provider_kind: Some("Denied"), ..baseline_error },
        WorkerErrorFixture { adapter_kind: Some("safe_point_rollback"), ..baseline_error },
        WorkerErrorFixture { workload_kind: Some("wrong_timer"), ..baseline_error },
    ] {
        write_worker_error_transcripts(&root, &[mutation], &[], 10, 11);
        assert_ne!(baseline, read_worker_errors(&case, &root).unwrap());
    }

    write_worker_error_transcripts(&root, &[], &[baseline_error], 10, 11);
    assert_ne!(baseline, read_worker_errors(&case, &root).unwrap());

    let second = WorkerErrorFixture { workload_kind: Some("wrong_timer"), ..baseline_error };
    write_worker_error_transcripts(&root, &[baseline_error, second], &[], 10, 11);
    let ordered = read_worker_errors(&case, &root).unwrap();
    write_worker_error_transcripts(&root, &[second, baseline_error], &[], 10, 11);
    assert_ne!(ordered, read_worker_errors(&case, &root).unwrap());

    let unknown =
        WorkerErrorFixture { provider_kind: Some("FutureProviderKind"), ..baseline_error };
    write_worker_error_transcripts(&root, &[unknown], &[], 10, 11);
    assert!(read_worker_errors(&case, &root).is_err());
    fs::remove_dir_all(root).unwrap();
}

#[test]
fn canonical_raw_layout_rejects_duplicate_alternate_missing_and_reordered_artifacts() {
    let canonical = worker_error_case();
    validate_canonical_raw_artifacts(&canonical).unwrap();

    let mut duplicate = canonical.clone();
    duplicate
        .artifacts
        .raw_execution
        .insert(1, raw_artifact_reference("cases/safe-point-unreachable/raw/source.jsonl"));
    assert_eq!(
        validate_canonical_raw_artifacts(&duplicate).unwrap_err().code,
        "noncanonical-stage2-raw-artifact-set"
    );

    let mut alternate = canonical.clone();
    alternate.artifacts.raw_execution[0].uri =
        "cases/safe-point-unreachable/alternate/source.jsonl".to_owned();
    assert_eq!(
        validate_canonical_raw_artifacts(&alternate).unwrap_err().code,
        "noncanonical-stage2-raw-artifact-set"
    );

    let mut missing = canonical.clone();
    missing.artifacts.raw_execution.pop();
    assert_eq!(
        validate_canonical_raw_artifacts(&missing).unwrap_err().code,
        "noncanonical-stage2-raw-artifact-set"
    );

    let mut reordered = canonical;
    reordered.artifacts.raw_execution.swap(0, 1);
    assert_eq!(
        validate_canonical_raw_artifacts(&reordered).unwrap_err().code,
        "noncanonical-stage2-raw-artifact-set"
    );
}

#[test]
fn outer_shape_rejects_overclaims_guards_cells_pairs_and_counts() {
    let evidence = evidence_bundle();
    let mut findings = Vec::new();
    validate_evidence_shape(&evidence, &mut findings);
    assert!(findings.is_empty(), "{findings:?}");

    let mut overclaim = evidence.clone();
    overclaim.claims.push(Stage2Claim::CrossIsaPortability);
    let mut findings = Vec::new();
    validate_evidence_shape(&overclaim, &mut findings);
    assert_has_code(&findings, "invalid-or-overstated-stage2-claim");

    let mut wrong_guards = evidence.clone();
    wrong_guards.claim_guards.strict_component_model_runtime_independence =
        Stage2ClaimBoundary::NotClaimed;
    let mut findings = Vec::new();
    validate_evidence_shape(&wrong_guards, &mut findings);
    assert_has_code(&findings, "invalid-stage2-claim-guards");

    let mut wrong_count = evidence.clone();
    wrong_count.completed_execution_count = 123;
    let mut findings = Vec::new();
    validate_evidence_shape(&wrong_count, &mut findings);
    assert_has_code(&findings, "wrong-stage2-execution-count");

    let manifest = matrix_manifest();
    let mut findings = Vec::new();
    validate_manifest_shape(&manifest, &evidence, &mut findings);
    assert!(findings.is_empty(), "{findings:?}");

    let mut missing = manifest.clone();
    missing.cells.pop();
    let mut findings = Vec::new();
    validate_manifest_shape(&missing, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-cell-set");

    let mut duplicate = manifest.clone();
    duplicate.cells[3] = duplicate.cells[0].clone();
    let mut findings = Vec::new();
    validate_manifest_shape(&duplicate, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-cell-set");

    let mut wrong_pair = manifest;
    wrong_pair.cells[0].requested_destination = Stage2Runtime::JcoNode;
    let mut findings = Vec::new();
    validate_manifest_shape(&wrong_pair, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-cell-manifest");

    let mut missing_jco = matrix_manifest();
    missing_jco.cells[1].source_translation_provenance = None;
    let mut findings = Vec::new();
    validate_manifest_shape(&missing_jco, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-cell-manifest");

    let provenance_mutations: [fn(&mut Stage2TranslationProvenance); 4] = [
        |provenance: &mut Stage2TranslationProvenance| {
            provenance.translation_options.push_str("-changed");
        },
        |provenance: &mut Stage2TranslationProvenance| {
            provenance.node_executable_path = "relative/node".to_owned();
        },
        |provenance: &mut Stage2TranslationProvenance| {
            provenance.node_executable_sha256 = "not-a-sha256".to_owned();
        },
        |provenance: &mut Stage2TranslationProvenance| {
            provenance.rpc_protocol_version += 1;
        },
    ];
    for mutate in provenance_mutations {
        let mut changed = matrix_manifest();
        mutate(
            changed.cells[1].source_translation_provenance.as_mut().expect("Jco source provenance"),
        );
        let mut findings = Vec::new();
        validate_manifest_shape(&changed, &evidence, &mut findings);
        assert_has_code(&findings, "invalid-stage2-cell-manifest");
    }

    let mut false_wasmtime = matrix_manifest();
    false_wasmtime.cells[0].source_translation_provenance =
        test_translation_provenance(Stage2Runtime::JcoNode);
    let mut findings = Vec::new();
    validate_manifest_shape(&false_wasmtime, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-cell-manifest");
}

#[test]
fn manifest_shape_rejects_missing_reordered_and_noncanonical_instantiation_observations() {
    let evidence = evidence_bundle();

    let mut missing = matrix_manifest();
    missing.cells[0].instantiation_observations.cases.pop();
    let mut findings = Vec::new();
    validate_manifest_shape(&missing, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-instantiation-observation-case-set");

    let mut reordered = matrix_manifest();
    reordered.cells[0].instantiation_observations.cases.swap(0, 1);
    let mut findings = Vec::new();
    validate_manifest_shape(&reordered, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-instantiation-observation-case-set");

    let mut wrong_source = matrix_manifest();
    wrong_source.cells[0].instantiation_observations.cases[0].source =
        Stage2InstantiationObservation::NotInstantiatedByCaseDesign {
            boundary: Stage2NotInstantiatedBoundary::BeforeCommit,
            reason: Stage2NotInstantiatedReason::SourceRetained,
        };
    let mut findings = Vec::new();
    validate_manifest_shape(&wrong_source, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-instantiation-observation-boundary");

    let mut wrong_destination = matrix_manifest();
    wrong_destination.cells[0].instantiation_observations.cases[0].destination =
        Stage2InstantiationObservation::NotInstantiatedByCaseDesign {
            boundary: Stage2NotInstantiatedBoundary::BeforeCommit,
            reason: Stage2NotInstantiatedReason::RecoveryRequired,
        };
    let mut findings = Vec::new();
    validate_manifest_shape(&wrong_destination, &evidence, &mut findings);
    assert_has_code(&findings, "invalid-stage2-instantiation-observation-boundary");

    let mut wrong_schema = matrix_manifest();
    wrong_schema.cells[0].instantiation_observations.schema_version.push_str("-future");
    let mut findings = Vec::new();
    validate_manifest_shape(&wrong_schema, &evidence, &mut findings);
    assert_has_code(&findings, "unsupported-stage2-instantiation-observations-schema");
}

#[test]
fn common_inputs_are_hash_checked_and_policy_bytes_are_digest_bound() {
    let root = temp_dir("common-input");
    let _ = fs::remove_dir_all(&root);
    fs::create_dir_all(root.join("inputs")).unwrap();
    let mut common = common_input(&root);
    let findings = validate_common_input(&common, &root);
    assert!(findings.is_empty(), "{findings:?}");

    common.original_component.sha256 = "f".repeat(64);
    let findings = validate_common_input(&common, &root);
    assert_has_code(&findings, "stage2-artifact-digest-mismatch");

    common.original_component.sha256 = sha256_hex(b"component");

    let mut policy: Stage2AuthorityPolicyInput =
        serde_json::from_slice(&fs::read(root.join("inputs/authority-policy.json")).unwrap())
            .unwrap();
    policy.cases[0].canonical_policy_bytes_hex = "00".to_owned();
    let policy_bytes = serde_json::to_vec(&policy).unwrap();
    fs::write(root.join("inputs/authority-policy.json"), &policy_bytes).unwrap();
    common.authority_policy.sha256 = sha256_hex(&policy_bytes);
    let findings = validate_common_input(&common, &root);
    assert_has_code(&findings, "inconsistent-stage2-authority-policy-case");

    fs::remove_dir_all(root).unwrap();
}

#[test]
fn accepted_registry_fixture_is_fixed_and_self_resigned_mutation_is_rejected() {
    let root = temp_dir("accepted-registry");
    let _ = fs::remove_dir_all(&root);
    fs::create_dir_all(root.join("inputs")).unwrap();
    let mut common = common_input(&root);

    assert_eq!(common.cases.len(), STAGE1_CASE_DEFINITIONS.len());
    assert_eq!(canonical_stage2_sha256(&common.cases).unwrap(), STAGE2_ACCEPTED_REGISTRY_SHA256);
    assert!(validate_common_input(&common, &root).is_empty());

    common.cases[11].fault_schedule.injections[0].action.push_str(";honest-semantic-change=true");
    let resigned_digest = canonical_stage2_sha256(&common.cases).unwrap();
    assert_ne!(resigned_digest, STAGE2_ACCEPTED_REGISTRY_SHA256);
    assert_eq!(resigned_digest.len(), 64);
    assert_has_code(
        &validate_common_input(&common, &root),
        "stage2-accepted-registry-lock-mismatch",
    );

    fs::remove_dir_all(root).unwrap();
}

#[test]
fn wit_world_name_and_self_resigned_bytes_cannot_escape_the_fixed_lock() {
    let root = temp_dir("wit-lock");
    let _ = fs::remove_dir_all(&root);
    fs::create_dir_all(root.join("inputs")).unwrap();
    let mut common = common_input(&root);

    common.wit_world.world_name = "visa:continuity/renamed-world@0.1.0".to_owned();
    assert_has_code(&validate_common_input(&common, &root), "wrong-stage2-wit-world-lock");

    common.wit_world.world_name = STAGE2_WIT_WORLD_NAME.to_owned();
    let mut changed_world = ACCEPTED_WIT_WORLD.to_vec();
    changed_world.extend_from_slice(b"\n// self-consistent but unaccepted mutation\n");
    fs::write(root.join("inputs/world.wit"), &changed_world).unwrap();
    common.wit_world.artifact.sha256 = sha256_hex(&changed_world);
    assert_has_code(&validate_common_input(&common, &root), "wrong-stage2-wit-world-lock");

    fs::remove_dir_all(root).unwrap();
}

#[test]
fn environment_runtime_identity_requires_every_exact_pin() {
    for (runtime, name, version) in [
        (
            Stage2Runtime::Wasmtime,
            STAGE2_WASMTIME_ENVIRONMENT_NAME,
            STAGE2_WASMTIME_ENVIRONMENT_VERSION,
        ),
        (
            Stage2Runtime::JcoNode,
            STAGE2_JCO_NODE_ENVIRONMENT_NAME,
            STAGE2_JCO_NODE_ENVIRONMENT_VERSION,
        ),
    ] {
        let identity =
            Stage1VersionedIdentity { name: name.to_owned(), version: version.to_owned() };
        assert!(runtime_identity_matches(runtime, &identity));

        let mut changed_name = identity.clone();
        changed_name.name.push_str("-fallback");
        assert!(!runtime_identity_matches(runtime, &changed_name));

        let mut changed_version = identity;
        changed_version.version.push_str("-fallback");
        assert!(!runtime_identity_matches(runtime, &changed_version));
    }
}

#[test]
fn observed_runtime_identity_requires_every_exact_pin() {
    let wasmtime = observed_runtime(
        "visa_wasmtime",
        STAGE2_WASMTIME_IMPLEMENTATION_VERSION,
        "wasmtime",
        STAGE2_WASMTIME_ENGINE_VERSION,
    );
    assert!(observed_runtime_matches(Stage2Runtime::Wasmtime, &wasmtime));
    assert_observed_field_mutations_are_rejected(Stage2Runtime::Wasmtime, &wasmtime);

    let jco = observed_runtime(
        "visa_jco_node+jco+js-component-bindgen",
        STAGE2_JCO_NODE_IMPLEMENTATION_VERSION,
        "node+v8",
        &format!("{STAGE2_NODE_VERSION}/v8-{STAGE2_V8_VERSION}"),
    );
    assert!(observed_runtime_matches(Stage2Runtime::JcoNode, &jco));
    assert_observed_field_mutations_are_rejected(Stage2Runtime::JcoNode, &jco);

    for changed_version in [
        STAGE2_JCO_NODE_IMPLEMENTATION_VERSION.replace("jco-1.25.2", "jco-1.25.3"),
        STAGE2_JCO_NODE_IMPLEMENTATION_VERSION.replace("bindgen-2.0.11", "bindgen-2.0.12"),
        STAGE2_JCO_NODE_IMPLEMENTATION_VERSION.replace("translator-45.0.1", "translator-45.0.2"),
    ] {
        let changed = observed_runtime(
            "visa_jco_node+jco+js-component-bindgen",
            &changed_version,
            "node+v8",
            &format!("{STAGE2_NODE_VERSION}/v8-{STAGE2_V8_VERSION}"),
        );
        assert!(!observed_runtime_matches(Stage2Runtime::JcoNode, &changed));
    }
    for changed_engine_version in [
        format!("24.15.1/v8-{STAGE2_V8_VERSION}"),
        format!("{STAGE2_NODE_VERSION}/v8-13.6.233.18-node.48"),
    ] {
        let changed = observed_runtime(
            "visa_jco_node+jco+js-component-bindgen",
            STAGE2_JCO_NODE_IMPLEMENTATION_VERSION,
            "node+v8",
            &changed_engine_version,
        );
        assert!(!observed_runtime_matches(Stage2Runtime::JcoNode, &changed));
    }
}

