#[test]
fn transcript_protocol_rejects_unknown_status_and_wrong_initialize_identity() {
    let mut committed = worker_error_case();
    committed.outcome = Stage1CaseOutcome::TimerRecreatedSingleExpiry;
    let worker = format!("{}-destination", committed.case_id);
    let baseline = wasmtime_transcript(
        &worker,
        &[("commit_destination", false), ("resume_destination", true)],
    );

    let unknown_status = mutate_transcript_protocol(&baseline, |stream, protocol| {
        if stream == "worker_response"
            && protocol.get("id").and_then(serde_json::Value::as_str) == Some("command-1")
        {
            protocol["outcome"]["status"] = serde_json::json!("future_status");
        }
    });
    assert_has_code(
        &audit_runtime_transcript_for_test(
            Stage2CellId::WasmtimeToWasmtime,
            &committed,
            "destination.jsonl",
            &unknown_status,
        ),
        "invalid-stage2-runtime-protocol-response-envelope",
    );

    let wrong_request_role = mutate_transcript_protocol(&baseline, |stream, protocol| {
        if stream == "parent_request"
            && protocol.pointer("/command/kind").and_then(serde_json::Value::as_str)
                == Some("initialize")
        {
            protocol["command"]["role"] = serde_json::json!("source");
        }
    });
    assert_has_code(
        &audit_runtime_transcript_for_test(
            Stage2CellId::WasmtimeToWasmtime,
            &committed,
            "destination.jsonl",
            &wrong_request_role,
        ),
        "invalid-stage2-runtime-initialize-request",
    );

    let wrong_response_case = mutate_transcript_protocol(&baseline, |_, protocol| {
        if protocol.pointer("/outcome/result/kind").and_then(serde_json::Value::as_str)
            == Some("initialized")
        {
            protocol["outcome"]["result"]["case_id"] = serde_json::json!("different-case");
        }
    });
    assert_has_code(
        &audit_runtime_transcript_for_test(
            Stage2CellId::WasmtimeToWasmtime,
            &committed,
            "destination.jsonl",
            &wrong_response_case,
        ),
        "invalid-stage2-runtime-initialize-response",
    );
}

#[test]
fn canonical_state_protocol_rejects_wrong_role_phase_and_minimal_view() {
    let committed = worker_error_case();
    let worker = format!("{}-source", committed.case_id);
    let baseline = wasmtime_transcript(&worker, &[("bootstrap_source", true)]);

    for mutation in ["role", "phase", "minimal"] {
        let changed = mutate_transcript_protocol(&baseline, |_, protocol| {
            if protocol.pointer("/outcome/result/kind").and_then(serde_json::Value::as_str)
                != Some("state")
            {
                return;
            }
            match mutation {
                "role" => {
                    protocol["outcome"]["result"]["view"]["role"] =
                        serde_json::json!("destination");
                }
                "phase" => {
                    protocol["outcome"]["result"]["view"]["canonical_phase"] =
                        serde_json::json!("committed");
                }
                "minimal" => {
                    protocol["outcome"]["result"]["view"] =
                        serde_json::json!({ "component_instantiated": true });
                }
                _ => unreachable!(),
            }
        });
        assert_has_code(
            &audit_runtime_transcript_for_test(
                Stage2CellId::WasmtimeToWasmtime,
                &committed,
                "source.jsonl",
                &changed,
            ),
            "invalid-stage2-runtime-canonical-state-observation",
        );
    }
}

