#[test]
fn normalized_cache_is_recomputed_instead_of_trusted() {
    let root = temp_dir("cache");
    let _ = fs::remove_dir_all(&root);
    fs::create_dir_all(root.join("normalized")).unwrap();
    let recomputed = Stage2NormalizedCellV1 {
        schema_version: STAGE2_NORMALIZED_TRACE_SCHEMA_VERSION.to_owned(),
        timer_equivalence: Stage2TimerEquivalenceProfile::PausedDurationZeroVsPositiveV1,
        derived_integrity_equivalence:
            Stage2DerivedIntegrityEquivalenceProfile::Stage1VerifiedDerivedDigestsV1,
        cases: Vec::new(),
    };
    let mutated = Stage2NormalizedCellV1 {
        schema_version: STAGE2_NORMALIZED_TRACE_SCHEMA_VERSION.to_owned(),
        timer_equivalence: Stage2TimerEquivalenceProfile::PausedDurationZeroVsPositiveV1,
        derived_integrity_equivalence:
            Stage2DerivedIntegrityEquivalenceProfile::Stage1VerifiedDerivedDigestsV1,
        cases: vec![normalized_case()],
    };
    let bytes = canonical_stage2_json_bytes(&mutated).unwrap();
    fs::write(root.join("normalized/wasmtime-to-wasmtime.json"), &bytes).unwrap();
    let mut manifest = cell_manifest(Stage2CellId::WasmtimeToWasmtime);
    manifest.normalized_observable_trace.sha256 = sha256_hex(&bytes);
    let mut findings = Vec::new();
    validate_normalized_cache(&root, &manifest, &recomputed, &mut findings);
    assert_has_code(&findings, "stage2-normalized-cache-mismatch");

    manifest.normalized_observable_trace.sha256 = "0".repeat(64);
    let mut findings = Vec::new();
    validate_normalized_cache(&root, &manifest, &recomputed, &mut findings);
    assert_has_code(&findings, "stage2-artifact-digest-mismatch");
    fs::remove_dir_all(root).unwrap();
}

