    let baseline_trace = trace(Stage1TraceRole::Source, 1, 50_000_000);
    let baseline = normalize_trace(baseline_trace.clone());

    let changed_identity = retarget_timer_resource(
        baseline_trace.clone(),
        EntityRef::initial(Identity::from_u128(404)),
    );
    assert_ne!(baseline, normalize_trace(changed_identity));

    let changed_generation = retarget_timer_resource(
        baseline_trace.clone(),
        EntityRef::new(Identity::from_u128(4), Generation(1)),
    );
    assert_ne!(baseline, normalize_trace(changed_generation));

    let mut changed_required_rights = baseline_trace;
    changed_required_rights.base_state.timer.claim.required_rights = Rights::TIMER_ARM;
    changed_required_rights.final_state.timer.claim.required_rights = Rights::TIMER_ARM;
    assert_ne!(baseline, normalize_trace(changed_required_rights));

    let baseline_case = normalized_case();
    let mut changed_claim_identity = baseline_case.clone();
    changed_claim_identity.binding_receipts[0].receipt.claim.identity = Identity::from_u128(405);
