#[test]
fn fr016_cancellation_rollback_cleanup_and_no_resurrection_are_retained() {
    let baseline_trace = trace(Stage1TraceRole::Source, 1, 50_000_000);
    let baseline = normalize_trace(baseline_trace.clone());

    let mut cancelled = baseline_trace.clone();
    cancelled.final_state.timer.status = TimerStatus::Cancelled;
    assert_ne!(baseline, normalize_trace(cancelled));

    let mut rolled_back = baseline_trace;
    rolled_back.entries.push(JournalEntry {
        version: CONTRACT_VERSION,
        position: JournalPosition(2),
        input_state: Digest::from_bytes([10; 32]),
        output_state: Digest::from_bytes([11; 32]),
        event: Event::new(Identity::from_u128(89), EventKind::SourceResumed),
    });
    assert_ne!(baseline, normalize_trace(rolled_back));

    let baseline_case = normalized_case();
    let mut without_cleanup = baseline_case.clone();
    without_cleanup.semantic_traces[0].final_state.preparation_cleanup = None;
    assert_ne!(baseline_case, without_cleanup);

    let mut changed_no_resurrection = baseline_case.clone();
    changed_no_resurrection.outcome = Stage1CaseOutcome::CleanupIdempotentNoResurrection;
    assert_ne!(baseline_case, changed_no_resurrection);
}

#[test]
fn normalized_case_retains_outcome_fault_authority_binding_and_cleanup_semantics() {
    let baseline = normalized_case();

    let mut changed = baseline.clone();
    changed.outcome = Stage1CaseOutcome::TimerPausedThenResumed;
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.fault_schedule.injections.swap(0, 1);
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.authority.fencing_epoch += 1;
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.authority.ownership = Stage1OwnershipStatus::SourceActive;
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.authority.source_fenced = false;
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.binding_receipts[0].receipt.exposed_rights = Rights::TIMER_CANCEL;
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.semantic_traces[0].final_state.preparation_cleanup = None;
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    changed.semantic_traces[0].entries.pop();
    assert_ne!(baseline, changed);

    let mut changed = baseline.clone();
    let duplicate = changed.semantic_traces[0].entries[0].clone();
    changed.semantic_traces[0].entries.push(duplicate);
    assert_ne!(baseline, changed);
}

fn trace(
    role: Stage1TraceRole,
    state_remaining: u64,
    request_remaining: u64,
) -> Stage1SemanticTraceArtifact {
    let mut base_state = state(role, state_remaining);
    let mut final_state = base_state.clone();
    let request = timer_request(request_remaining);
    base_state.operations.push(OperationRecord::prepared(request.clone()));
    final_state.operations.push(OperationRecord::prepared(request.clone()));
    let entry = JournalEntry {
        version: CONTRACT_VERSION,
        position: JournalPosition(1),
        input_state: Digest::from_bytes([1; 32]),
        output_state: Digest::from_bytes([2; 32]),
        event: Event::new(Identity::from_u128(77), EventKind::EffectPrepared { request }),
    };
    Stage1SemanticTraceArtifact {
        schema_version: STAGE1_SEMANTIC_TRACE_SCHEMA_VERSION.to_owned(),
        role,
        scope: Stage1JournalScope {
            node: base_state.activation.node,
            component: base_state.component.identity,
        },
        base_cursor: JournalPosition::ORIGIN,
        base_state,
        entries: vec![entry],
        final_state,
        claimed_final: true,
    }
}

fn retarget_timer_resource(
    mut trace: Stage1SemanticTraceArtifact,
    resource: EntityRef,
) -> Stage1SemanticTraceArtifact {
    for state in [&mut trace.base_state, &mut trace.final_state] {
        state.timer.claim.resource = resource;
        state.authorities[0].resource = resource;
        state.operations[0].request.resource = resource;
    }
    if let EventKind::EffectPrepared { request } = &mut trace.entries[0].event.kind {
        request.resource = resource;
    }
    trace
}

fn state(role: Stage1TraceRole, remaining: u64) -> CanonicalState {
    let component = EntityRef::initial(Identity::from_u128(1));
    let node = NodeIdentity::new(Identity::from_u128(match role {
        Stage1TraceRole::Source => 2,
        Stage1TraceRole::Destination => 3,
    }));
    let timer = EntityRef::initial(Identity::from_u128(4));
    let key_value = EntityRef::initial(Identity::from_u128(5));
    let timer_rights = Rights::TIMER_ARM.union(Rights::TIMER_CANCEL);
    let claims = ResourceClaims {
        timer: TimerClaim {
            resource: timer,
            clock: TimerClock::PausedMonotonicDuration,
            required_rights: timer_rights,
        },
        key_value: KeyValueClaim {
            resource: key_value,
            namespace: Identity::from_u128(6),
            required_rights: Rights::KV_READ,
            delivery: contract_core::DeliveryPolicy::Deduplicated,
        },
    };
    let authorities = vec![AuthorityGrant::active_root(
        EntityRef::initial(Identity::from_u128(7)),
        component,
        timer,
        timer_rights,
    )];
    let mut state = CanonicalState::dormant(
        component,
        node,
        Digest::from_bytes([3; 32]),
        Digest::from_bytes([4; 32]),
        SchemaVersion::new(1, 0),
        claims,
        authorities,
    );
    state.activation.role = match role {
        Stage1TraceRole::Source => ActivationRole::Source,
        Stage1TraceRole::Destination => ActivationRole::Destination,
    };
    state.activation.status = ActivationStatus::Active;
    state.ownership = Ownership::owned(node, LeaseEpoch(1));
    state.timer.status = TimerStatus::Armed { remaining: LogicalDurationNanos(remaining) };
    state.evidence.push(EvidenceRef {
        identity: Identity::from_u128(8),
        kind: EvidenceKind::EffectOutcome,
        digest: Digest::from_bytes([9; 32]),
    });
    state
}

fn timer_request(remaining: u64) -> EffectRequest {
    let component = EntityRef::initial(Identity::from_u128(1));
    EffectRequest {
        operation: Identity::from_u128(10),
        idempotency_key: IdempotencyKey::from_u128(11),
        causal_parent: None,
        node: NodeIdentity::new(Identity::from_u128(2)),
        subject: component,
        resource: EntityRef::initial(Identity::from_u128(4)),
        authority: EntityRef::initial(Identity::from_u128(7)),
        lease_epoch: LeaseEpoch(1),
        request_digest: Digest::from_bytes([5; 32]),
        kind: EffectKind::TimerArm { remaining: LogicalDurationNanos(remaining) },
    }
}

fn snapshot() -> SnapshotEnvelope {
    let state = state(Stage1TraceRole::Source, 1);
    let snapshot = SnapshotRecord {
        handoff: Identity::from_u128(20),
        snapshot: Identity::from_u128(21),
        journal_position: JournalPosition(1),
        evidence: EvidenceRef {
            identity: Identity::from_u128(22),
            kind: EvidenceKind::SnapshotIntegrity,
            digest: Digest::from_bytes([6; 32]),
        },
    };
    SnapshotEnvelope {
        version: CONTRACT_VERSION,
        body: SnapshotBody {
            version: CONTRACT_VERSION,
            profile_version: SchemaVersion::new(1, 0),
            snapshot,
            source_node: state.activation.node,
            component: state.component,
            component_digest: state.component_digest,
            profile_digest: state.profile_digest,
            source_lease_epoch: LeaseEpoch(1),
            portable_state: b"VISACS01state".to_vec(),
            claims: state.claims(),
            timer: TimerDisposition::Pending {
                remaining: LogicalDurationNanos(1),
                arm_operation: Identity::from_u128(10),
            },
            key_value_last_version: None,
            key_value_last_operation: None,
            extensions: Vec::new(),
            authorities: state.authorities,
            operations: Vec::new(),
        },
        integrity: Digest::from_bytes([7; 32]),
    }
}

fn prepared_request(entry: &JournalEntry) -> &EffectRequest {
    let EventKind::EffectPrepared { request } = &entry.event.kind else {
        panic!("expected EffectPrepared");
    };
    request
}

fn timer_arm_remaining(request: &EffectRequest) -> u64 {
    let EffectKind::TimerArm { remaining } = request.kind else {
        panic!("expected TimerArm");
    };
    remaining.0
}

fn timer_status_remaining(state: &CanonicalState) -> u64 {
    let TimerStatus::Armed { remaining } = state.timer.status else {
        panic!("expected armed timer");
    };
    remaining.0
}

