fn assert_observed_field_mutations_are_rejected(
    runtime: Stage2Runtime,
    expected: &ObservedRuntimeIdentity,
) {
    let changed = observed_runtime(
        &format!("{}-fallback", expected.implementation),
        &expected.implementation_version,
        &expected.engine,
        &expected.engine_version,
    );
    assert!(!observed_runtime_matches(runtime, &changed));

    let changed = observed_runtime(
        &expected.implementation,
        &format!("{}-fallback", expected.implementation_version),
        &expected.engine,
        &expected.engine_version,
    );
    assert!(!observed_runtime_matches(runtime, &changed));

    let changed = observed_runtime(
        &expected.implementation,
        &expected.implementation_version,
        &format!("{}-fallback", expected.engine),
        &expected.engine_version,
    );
    assert!(!observed_runtime_matches(runtime, &changed));

    let changed = observed_runtime(
        &expected.implementation,
        &expected.implementation_version,
        &expected.engine,
        &format!("{}-fallback", expected.engine_version),
    );
    assert!(!observed_runtime_matches(runtime, &changed));
}

fn common_input(root: &std::path::Path) -> Stage2CommonInputManifest {
    let component = b"component".to_vec();
    let world = ACCEPTED_WIT_WORLD.to_vec();
    let profile = b"profile".to_vec();
    let configuration = b"configuration".to_vec();
    assert_eq!(sha256_hex(&world), STAGE2_WIT_WORLD_SHA256);
    fs::write(root.join("inputs/component.wasm"), &component).unwrap();
    fs::write(root.join("inputs/world.wit"), &world).unwrap();
    fs::write(root.join("inputs/profile.json"), &profile).unwrap();
    fs::write(root.join("inputs/configuration.json"), &configuration).unwrap();

    let cases = accepted_common_cases();
    let policy: Stage2AuthorityPolicyInput =
        serde_json::from_str(ACCEPTED_AUTHORITY_POLICY_JSON).unwrap();
    let policy_bytes = serde_json::to_vec(&policy).unwrap();
    fs::write(root.join("inputs/authority-policy.json"), &policy_bytes).unwrap();

    Stage2CommonInputManifest {
        schema_version: crate::STAGE2_COMMON_INPUT_SCHEMA_VERSION.to_owned(),
        original_component: artifact("inputs/component.wasm", &component),
        wit_world: Stage2WitWorldInput {
            world_name: STAGE2_WIT_WORLD_NAME.to_owned(),
            artifact: artifact("inputs/world.wit", &world),
        },
        profile: artifact("inputs/profile.json", &profile),
        profile_sha256: "7".repeat(64),
        configuration: artifact("inputs/configuration.json", &configuration),
        config_sha256: "8".repeat(64),
        authority_policy: artifact("inputs/authority-policy.json", &policy_bytes),
        authority_policy_sha256: "9".repeat(64),
        component_state_codec: Stage1VersionedIdentity {
            name: crate::STAGE2_COMPONENT_STATE_CODEC_NAME.to_owned(),
            version: crate::STAGE2_COMPONENT_STATE_CODEC_VERSION.to_owned(),
        },
        stage1_evidence_schema_version: STAGE1_EVIDENCE_SCHEMA_VERSION.to_owned(),
        stage1_semantic_trace_schema_version: STAGE1_SEMANTIC_TRACE_SCHEMA_VERSION.to_owned(),
        cases,
    }
}

fn accepted_common_cases() -> Vec<Stage2CommonCaseInput> {
    serde_json::from_str(ACCEPTED_COMMON_CASES_JSON).unwrap()
}

fn artifact(uri: &str, bytes: &[u8]) -> Stage2ArtifactReference {
    Stage2ArtifactReference { uri: uri.to_owned(), sha256: sha256_hex(bytes) }
}

#[derive(Clone, Copy)]
struct Fr016AssertionFixture {
    name: &'static str,
    detail: &'static str,
    observed_at_unix_ms: u64,
}

#[derive(Clone, Copy)]
struct Fr016ProjectionConfig {
    started_at_unix_ms: u64,
    finished_at_unix_ms: u64,
    trace_uri: &'static str,
    snapshot_uri: &'static str,
    destination_remaining: u64,
    source_pid: u32,
    destination_pid: u32,
    worker_message: &'static str,
    assertions: [Fr016AssertionFixture; 2],
    raw_timing_samples: [u64; 2],
    pretty_snapshot_json: bool,
}

struct Fr016ProjectionOutput {
    normalized: Stage2NormalizedCellV1,
    raw_snapshot_size_bytes: u64,
}

fn fr016_projection_config() -> Fr016ProjectionConfig {
    Fr016ProjectionConfig {
        started_at_unix_ms: 1_000,
        finished_at_unix_ms: 2_000,
        trace_uri: "cases/performance-observations/generated/destination-trace.json",
        snapshot_uri: "cases/performance-observations/generated/snapshot.json",
        destination_remaining: 41,
        source_pid: 10,
        destination_pid: 11,
        worker_message: "engine-specific human message",
        assertions: [
            Fr016AssertionFixture {
                name: "first-semantic-assertion",
                detail: "human assertion detail A",
                observed_at_unix_ms: 1_500,
            },
            Fr016AssertionFixture {
                name: "second-semantic-assertion",
                detail: "human assertion detail B",
                observed_at_unix_ms: 1_600,
            },
        ],
        raw_timing_samples: [100, 110],
        pretty_snapshot_json: false,
    }
}

fn normalize_fr016_projection(
    root: &std::path::Path,
    config: Fr016ProjectionConfig,
) -> Fr016ProjectionOutput {
    const CASE_ID: &str = "performance-observations";
    let _ = fs::remove_dir_all(root);
    fs::create_dir_all(root.join("cases/performance-observations/raw")).unwrap();

    let trace_bytes = serde_json::to_vec(&trace(
        Stage1TraceRole::Destination,
        config.destination_remaining,
        config.destination_remaining,
    ))
    .unwrap();
    write_fixture_artifact(root, config.trace_uri, &trace_bytes);

    let snapshot_bytes = if config.pretty_snapshot_json {
        serde_json::to_vec_pretty(&snapshot()).unwrap()
    } else {
        serde_json::to_vec(&snapshot()).unwrap()
    };
    write_fixture_artifact(root, config.snapshot_uri, &snapshot_bytes);
    let raw_snapshot_size_bytes = u64::try_from(snapshot_bytes.len()).unwrap();

    let structured_error = WorkerErrorFixture::baseline(config.worker_message);
    let source_bytes = worker_error_transcript(
        "performance-observations-source",
        config.source_pid,
        &[structured_error],
    );
    let destination_bytes = worker_error_transcript(
        "performance-observations-destination",
        config.destination_pid,
        &[],
    );
    let assertion_bytes = assertion_transcript(&config.assertions);
    let performance_bytes = serde_json::to_vec(&serde_json::json!({
        "handoff_interruption_nanos": config.raw_timing_samples,
        "raw_serialized_snapshot_size_bytes": raw_snapshot_size_bytes,
    }))
    .unwrap();
    for (name, bytes) in [
        ("source.jsonl", source_bytes.as_slice()),
        ("destination.jsonl", destination_bytes.as_slice()),
        ("assertions.jsonl", assertion_bytes.as_slice()),
        ("performance.json", performance_bytes.as_slice()),
    ] {
        write_fixture_artifact(root, &format!("cases/{CASE_ID}/raw/{name}"), bytes);
    }

    let raw_reference = |name: &str, bytes: &[u8]| {
        fr016_artifact_reference(CASE_ID, &format!("cases/{CASE_ID}/raw/{name}"), bytes)
    };
    let case = Stage1CaseEvidence {
        case_id: CASE_ID.to_owned(),
        execution_id: "execution".to_owned(),
        handoff_id: "handoff".to_owned(),
        snapshot_id: "snapshot".to_owned(),
        case_config_sha256: "1".repeat(64),
        case_policy_sha256: "2".repeat(64),
        outcome: Stage1CaseOutcome::RawPerformanceRecorded,
        exit_status: 0,
        fault_schedule: Stage1FaultSchedule {
            schedule_id: "none".to_owned(),
            injections: Vec::new(),
        },
        authority: Stage1AuthorityEvidence {
            enforcement_policy_sha256: "3".repeat(64),
            source_authority_root_sha256: "4".repeat(64),
            destination_authority_root_sha256: "5".repeat(64),
            source_lease_epoch: 1,
            destination_lease_epoch: Some(2),
            fencing_epoch: 2,
            ownership: Stage1OwnershipStatus::DestinationActive,
            source_fenced: true,
        },
        artifacts: Stage1CaseArtifacts {
            snapshot: Some(fr016_artifact_reference(CASE_ID, config.snapshot_uri, &snapshot_bytes)),
            semantic_traces: vec![fr016_artifact_reference(
                CASE_ID,
                config.trace_uri,
                &trace_bytes,
            )],
            binding_receipts: Vec::new(),
            raw_execution: vec![
                raw_reference("source.jsonl", &source_bytes),
                raw_reference("destination.jsonl", &destination_bytes),
                raw_reference("assertions.jsonl", &assertion_bytes),
                raw_reference("performance.json", &performance_bytes),
            ],
        },
        state: Stage1StateEvidence {
            state_sha256: "6".repeat(64),
            replay_state_sha256: "6".repeat(64),
            snapshot_sha256: Some(sha256_hex(&snapshot_bytes)),
            trace_sha256s: vec![sha256_hex(&trace_bytes)],
        },
    };
    let bundle =
        fr016_bundle(case, config, raw_snapshot_size_bytes, sha256_hex(&performance_bytes));
    let normalized = normalize_stage2_cell(&bundle, root).unwrap();
    Fr016ProjectionOutput { normalized, raw_snapshot_size_bytes }
}

fn fr016_bundle(
    case: Stage1CaseEvidence,
    config: Fr016ProjectionConfig,
    raw_snapshot_size_bytes: u64,
    raw_performance_sha256: String,
) -> Stage1EvidenceBundle {
    let versioned = |name: &str, version: &str| Stage1VersionedIdentity {
        name: name.to_owned(),
        version: version.to_owned(),
    };
    let provenance_reference = |uri: &str| Stage1ProvenanceArtifactReference {
        uri: uri.to_owned(),
        sha256: "a".repeat(64),
    };
    Stage1EvidenceBundle {
        schema_version: STAGE1_EVIDENCE_SCHEMA_VERSION.to_owned(),
        capability_id: STAGE1_CAPABILITY_ID.to_owned(),
        bundle_id: "bundle".to_owned(),
        evidence_kind: Stage1EvidenceKind::Execution,
        claims: vec![Stage1Claim::CooperativeStatefulComponentHandoff],
        started_at_unix_ms: config.started_at_unix_ms,
        finished_at_unix_ms: config.finished_at_unix_ms,
        environment: Stage1ExecutionEnvironment {
            carrier: versioned("carrier", "1"),
            source_runtime: versioned("source", "1"),
            destination_runtime: versioned("destination", "1"),
            source_isa: Stage1IsaIdentity {
                architecture: "x86_64".to_owned(),
                abi: "linux-gnu".to_owned(),
            },
            destination_isa: Stage1IsaIdentity {
                architecture: "x86_64".to_owned(),
                abi: "linux-gnu".to_owned(),
            },
            substrate: versioned("substrate", "1"),
            provider: Stage1ProviderIdentity {
                implementation: versioned("provider", "1"),
                durable: true,
                mock: false,
            },
            authority_enforcement: Stage1AuthorityEnforcementIdentity {
                implementation: versioned("authority", "1"),
                policy_sha256: "3".repeat(64),
            },
            resource_profiles: Vec::new(),
        },
        provenance: Stage1Provenance {
            component_sha256: "8".repeat(64),
            profile_sha256: "9".repeat(64),
            config_sha256: "1".repeat(64),
            source_sha256: "a".repeat(64),
            toolchain_sha256: "b".repeat(64),
            executable_sha256: "c".repeat(64),
            artifacts: Stage1ProvenanceArtifacts {
                component: provenance_reference("provenance/component.wasm"),
                profile: provenance_reference("provenance/profile.json"),
                source_manifest: provenance_reference("provenance/source.json"),
                toolchain: provenance_reference("provenance/toolchain.txt"),
                build_source_manifest: provenance_reference("provenance/build-source.json"),
                build_toolchain: provenance_reference("provenance/build-toolchain.txt"),
                executable: provenance_reference("provenance/executable"),
                matrix_manifest: provenance_reference("provenance/matrix.json"),
            },
        },
        cases: vec![case],
        performance_observations: vec![
            Stage1PerformanceObservation {
                metric: Stage1PerformanceMetric::HandoffInterruption,
                unit: Stage1PerformanceUnit::Nanoseconds,
                samples: config.raw_timing_samples.to_vec(),
                execution_id: "execution".to_owned(),
                raw_artifact_sha256: raw_performance_sha256.clone(),
            },
            Stage1PerformanceObservation {
                metric: Stage1PerformanceMetric::SnapshotSize,
                unit: Stage1PerformanceUnit::Bytes,
                samples: vec![raw_snapshot_size_bytes],
                execution_id: "execution".to_owned(),
                raw_artifact_sha256: raw_performance_sha256,
            },
        ],
    }
}

fn fr016_artifact_reference(case_id: &str, uri: &str, bytes: &[u8]) -> Stage1ArtifactReference {
    Stage1ArtifactReference {
        uri: uri.to_owned(),
        sha256: sha256_hex(bytes),
        bundle_id: "bundle".to_owned(),
        case_id: case_id.to_owned(),
        execution_id: "execution".to_owned(),
        handoff_id: "handoff".to_owned(),
        snapshot_id: "snapshot".to_owned(),
        component_sha256: "8".repeat(64),
        profile_sha256: "9".repeat(64),
    }
}

fn write_fixture_artifact(root: &std::path::Path, uri: &str, bytes: &[u8]) {
    let path = root.join(uri);
    fs::create_dir_all(path.parent().unwrap()).unwrap();
    fs::write(path, bytes).unwrap();
}

fn assertion_transcript(assertions: &[Fr016AssertionFixture]) -> Vec<u8> {
    let mut bytes = Vec::new();
    for assertion in assertions {
        bytes.extend_from_slice(
            &serde_json::to_vec(&serde_json::json!({
                "name": assertion.name,
                "detail": assertion.detail,
                "observed_at_unix_ms": assertion.observed_at_unix_ms,
            }))
            .unwrap(),
        );
        bytes.push(b'\n');
    }
    bytes
}

