#[derive(Clone, Copy)]
struct WorkerErrorFixture {
    code: &'static str,
    message: &'static str,
    retryable: Option<bool>,
    provider_kind: Option<&'static str>,
    adapter_kind: Option<&'static str>,
    workload_kind: Option<&'static str>,
}

impl WorkerErrorFixture {
    fn baseline(message: &'static str) -> Self {
        Self {
            code: "adapter",
            message,
            retryable: Some(false),
            provider_kind: Some("NotFound"),
            adapter_kind: Some("workload"),
            workload_kind: Some("safe_point_unavailable"),
        }
    }
}

fn worker_error_transcript(worker: &str, pid: u32, errors: &[WorkerErrorFixture]) -> Vec<u8> {
    let mut bytes = Vec::new();
    for (index, error) in errors.iter().enumerate() {
        let request_id = format!("request-{index}");
        let request = serde_json::json!({
            "version": 1,
            "id": request_id,
            "command": { "kind": "read" },
        });
        let response = serde_json::json!({
            "version": 1,
            "id": request_id,
            "outcome": {
                "status": "error",
                "error": {
                    "code": error.code,
                    "message": error.message,
                    "retryable": error.retryable,
                    "provider_kind": error.provider_kind,
                    "adapter_kind": error.adapter_kind,
                    "workload_kind": error.workload_kind,
                }
            }
        });
        let request_envelope = serde_json::json!({
            "worker": worker,
            "pid": pid,
            "sequence": index * 2 + 1,
            "stream": "parent_request",
            "line": request.to_string(),
        });
        let response_envelope = serde_json::json!({
            "worker": worker,
            "pid": pid,
            "sequence": index * 2 + 2,
            "stream": "worker_response",
            "line": response.to_string(),
        });
        for envelope in [request_envelope, response_envelope] {
            bytes.extend_from_slice(&serde_json::to_vec(&envelope).unwrap());
            bytes.push(b'\n');
        }
    }
    bytes
}

fn write_worker_error_transcripts(
    root: &std::path::Path,
    source_errors: &[WorkerErrorFixture],
    destination_errors: &[WorkerErrorFixture],
    source_pid: u32,
    destination_pid: u32,
) {
    fs::write(
        root.join("cases/safe-point-unreachable/raw/source.jsonl"),
        worker_error_transcript("safe-point-unreachable-source", source_pid, source_errors),
    )
    .unwrap();
    fs::write(
        root.join("cases/safe-point-unreachable/raw/destination.jsonl"),
        worker_error_transcript(
            "safe-point-unreachable-destination",
            destination_pid,
            destination_errors,
        ),
    )
    .unwrap();
}
